import React, { useState, useEffect, useRef } from "react";
import { useSocket } from "../context/SocketContext";
import YouTube from "react-youtube";

function fmt(sec) {
  if (!sec || isNaN(sec)) return "0:00";
  return `${Math.floor(sec / 60)}:${String(
    Math.floor(sec % 60)
  ).padStart(2, "0")}`;
}

export default function Player() {
  const { state, emit } = useSocket();

  const playerRef = useRef(null);

  const [localPos, setLocalPos] = useState(0);

  const song = state?.currentSong;

  // YouTube Ready
  const onReady = (event) => {
    playerRef.current = event.target;
  };

  // Play Pause Sync
  useEffect(() => {
    if (!playerRef.current) return;

    try {
      if (state?.isPlaying) {
        playerRef.current.playVideo();
      } else {
        playerRef.current.pauseVideo();
      }
    } catch {}
  }, [state?.isPlaying]);

  // Seek Sync
  useEffect(() => {
    if (!playerRef.current) return;

    try {
      const current = playerRef.current.getCurrentTime();

      if (Math.abs(current - (state?.position || 0)) > 2) {
        playerRef.current.seekTo(state.position || 0, true);
      }
    } catch {}
  }, [state?.position]);

  // Update Current Position
  useEffect(() => {
    const interval = setInterval(() => {
      try {
        if (playerRef.current) {
          setLocalPos(playerRef.current.getCurrentTime());
        }
      } catch {}
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  const handlePlayPause = () => {
    emit("play_pause", {
      isPlaying: !state?.isPlaying,
    });
  };

  const handleNext = () => {
    emit("next_song");
  };

  const handlePrev = () => {
    emit("prev_song");
  };

  const handleSeekChange = (e) => {
    const pos = Number(e.target.value);

    setLocalPos(pos);

    if (playerRef.current) {
      playerRef.current.seekTo(pos, true);
    }

    emit("seek", {
      position: pos,
    });
  };

  const handleSyncToggle = () => {
    emit("toggle_sync", {
      syncEnabled: !state?.syncEnabled,
    });
  };

  const progress =
    song?.duration && song.duration > 0
      ? (localPos / song.duration) * 100
      : 0;

  return (
    <div className="player">
      {song?.videoId && (
        <div style={{ display: "none" }}>
          <YouTube
            videoId={song.videoId}
            onReady={onReady}
            opts={{
              width: "0",
              height: "0",
              playerVars: {
                autoplay: 1,
              },
            }}
          />
        </div>
      )}

      <div className="player-info">
        {song ? (
          <>
            <img
              src={song.cover}
              alt={song.title}
              className="player-cover"
              onError={(e) => {
                e.target.src =
                  "https://via.placeholder.com/46/1a1a2e/fff?text=♪";
              }}
            />

            <div className="player-meta">
              <span className="player-title">{song.title}</span>
              <span className="player-artist">{song.artist}</span>
            </div>
          </>
        ) : (
          <span className="player-empty">No song playing</span>
        )}
      </div>

      <div className="player-center">
        <div className="player-ctrls">
          <button
            className="ctrl"
            onClick={handlePrev}
          >
            ⏮
          </button>

          <button
            className="ctrl play"
            onClick={handlePlayPause}
            disabled={!song}
          >
            {state?.isPlaying ? "⏸" : "▶"}
          </button>

          <button
            className="ctrl"
            onClick={handleNext}
          >
            ⏭
          </button>
        </div>

        <div className="player-progress">
          <span className="ptime">
            {fmt(localPos)}
          </span>

          <div className="ptrack">
            <div
              className="pfill"
              style={{
                width: `${progress}%`,
              }}
            />

            <input
              type="range"
              min={0}
              max={song?.duration || 300}
              value={localPos}
              step={1}
              className="pinput"
              onChange={handleSeekChange}
            />
          </div>

          <span className="ptime">
            {fmt(song?.duration)}
          </span>
        </div>
      </div>

      <div className="player-right">
        <button
          className={`sync-btn ${
            state?.syncEnabled ? "on" : "off"
          }`}
          onClick={handleSyncToggle}
        >
          🔄 {state?.syncEnabled ? "Live Sync" : "Sync Off"}
        </button>
      </div>
    </div>
  );
}